const BLACKLIST = [
  'facebook.com','instagram.com','linkedin.com','twitter.com','x.com',
  'youtube.com','tiktok.com','reddit.com','pinterest.com','threads.net',
  'amazon.com','amazon.it','amazon.co.uk','amazon.de',
  'ebay.com','ebay.it','etsy.com','aliexpress.com','alibaba.com',
  'catawiki.com','vinted.com','subito.it','yelp.com','tripadvisor.com',
  'trustpilot.com','wikipedia.org','google.com','bing.com','crunchbase.com'
];

const CONFIDENCE_THRESHOLD = 2.5;


function normalize(text) {
  return (text || '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]+/g, ' ');
}

function tokenize(name) {
  const stopwords = new Set([
    "the","and","of","di","e","srl","sas","spa","sa","ltd","llc",
    "inc","co","company","corp","group","holding","holdings"
  ]);

  return normalize(name)
    .split(/\s+/)
    .filter(t => t && !stopwords.has(t) && t.length > 1);
}

function extractDomain(url) {
  let d = url.replace(/^https?:\/\//i, '');
  d = d.replace(/^www\./i, '');
  return d.split('/')[0].toLowerCase();
}

function registrableDomain(host) {
  host = host.replace(/^www\./, '');
  const parts = host.split('.');
  if (parts.length <= 2) return host;
  return parts.slice(-2).join('.');
}

function isBlacklisted(url) {
  const d = extractDomain(url);
  return BLACKLIST.some(b => d === b || d.endsWith('.' + b));
}

function scoreCandidate(item, tokens, country) {
  let score = 0;

  const url = item.url;
  const title = item.title || '';
  const snippet = item.snippet || '';
  const rank = item.rank ?? 0;

  const parsedDomain = extractDomain(url);
  const domain = registrableDomain(parsedDomain);

  const domainCore = domain.split('.')[0];
  const domainCompact = domainCore.replace(/[^a-z0-9]/g, '');

  const tokenSet = new Set(tokens);
  const domainTokens = domainCore.split(/[^a-z0-9]+/).filter(Boolean);

  // 1. DOMAIN TOKEN MATCH (3.0)
  const domainHits = domainTokens.filter(t => tokenSet.has(t)).length;
  score += 3.0 * domainHits;

  // 2. SUBSTRING MATCH (1.5)
  let substringHits = 0;
  for (const t of tokens) {
    if (t.length >= 3 && domainCompact.includes(t)) substringHits++;
  }
  score += 1.5 * Math.max(0, substringHits - domainHits);

  // 3. FULL NAME MATCH (2.0)
  const joined = tokens.join('');
  if (joined && domainCompact.includes(joined)) {
    score += 2.0;
  }

  // 4. TITLE + SNIPPET MATCH (0.4)
  const haystack = normalize(title + ' ' + snippet);
  let textHits = 0;
  for (const t of tokenSet) {
    if (haystack.includes(t)) textHits++;
  }
  score += 0.4 * textHits;

  // 5. HOMEPAGE BONUS (0.5)
  const path = url.split(parsedDomain)[1] || '';
  if (!path || path === '/') score += 0.5;
  else if (path.split('/').length > 3) score -= 0.3;

  // 6. RANK BONUS (0.3 decay)
  score += Math.max(0, 0.3 - 0.03 * rank);

  // 7. BLOG / BUILDER PENALTY (-1.5)
  if (
    parsedDomain.includes('blogspot') ||
    parsedDomain.includes('wordpress') ||
    parsedDomain.includes('wixsite') ||
    parsedDomain.includes('weebly')
  ) {
    score -= 1.5;
  }

  return score;
}

function process(inputItem, scraperItem) {
  const inputJson = inputItem?.json ?? null;
  const scraperJson = scraperItem?.json ?? null;

  const searchResults = Array.isArray(inputJson)
    ? (inputJson[0]?.data ?? inputJson)
    : (inputJson?.data ?? []);

  const filtered = searchResults.filter(r => !isBlacklisted(r.url || ''));

  const businessName =
    scraperJson?.business_name ||
    scraperJson?.data?.name ||
    '';
  console.log("businessName", businessName)
  const tokens = tokenize(businessName);

  let bestScore = -Infinity;
  let bestUrl = null;

  const scored = filtered.map(r => {
    const score = scoreCandidate(r, tokens);
    return { ...r, score };
  });

  for (const r of scored) {
    if (r.score > bestScore) {
      bestScore = r.score;
      bestUrl = r.url;
    }
  }

  return {
    bestUrl: bestScore >= CONFIDENCE_THRESHOLD ? bestUrl : null,
    score: bestScore,
    threshold: CONFIDENCE_THRESHOLD,
    passed: bestScore >= CONFIDENCE_THRESHOLD,
    businessName,
    ranked: scored.sort((a,b) => b.score - a.score)
  };
}

