const items = $input.all();

const result = items.map(item => {
  let urls =
    item.json?.data?.data?.data ?? // format scraper
    item.json?.data ??             // format simple
    null;

  // kalau string -> ubah jadi array
  if (typeof urls === "string") {
    urls = [urls];
  }

  // fallback null
  if (!Array.isArray(urls) || urls.length === 0) {
    return { json: { url: null } };
  }

  // sorting priority:
  // 1. yang punya slash lebih banyak
  // 2. kalau sama, string paling panjang
  // 3. kalau masih sama, ambil index pertama
  const bestUrl = urls.reduce((best, current) => {
    if (!best) return current;

    const bestSlash = (best.match(/\//g) || []).length;
    const currentSlash = (current.match(/\//g) || []).length;

    // prioritas slash lebih banyak
    if (currentSlash > bestSlash) {
      return current;
    }

    // kalau slash sama -> ambil string lebih panjang
    if (
      currentSlash === bestSlash &&
      current.length > best.length
    ) {
      return current;
    }

    return best;
  }, null);

  return {
    json: {
      url: bestUrl
    }
  };
});

return result;

